mapper.insert:
		/*
			 토론 댓글 등록
			 ForumCmntDAO.insertCmnt
		*/
        INSERT INTO TB_LMS_DSCS_CMNT (
              DSCS_CMNT_ID
            , DSCS_ATCL_ID
            , USER_ID
            , UP_CMNT_ID
            , CMNT_CTS
            , CMNT_CTS_LEN
            , RSPNS_REQYN
            , EMT_TYCD
            , DELYN
            , RGTR_ID
            , REG_DTTM
            , MDFR_ID
            , MOD_DTTM
        ) VALUES (
              #{cmntSn}
            , #{atclSn}
            , #{rgtrId}
            , #{parCmntSn}
            , #{cmntCts}
            , #{cmntCtsLen}
            , #{ansReqYn}
            , TO_CHAR(#{emoticonNo})
            , 'N'
            , #{rgtrId}
            , FN_DTTM()
            , #{mdfrId}
            , FN_DTTM()
        )

mapper.update:
		/*
			 토론방 댓글 수정
			 ForumCmntDAO.updateCmnt
		*/
        UPDATE TB_LMS_DSCS_CMNT
        SET CMNT_CTS = #{cmntCts}
          , CMNT_CTS_LEN = #{cmntCtsLen}
          , RSPNS_REQYN = #{ansReqYn}
          , MOD_DTTM = FN_DTTM()
          , MDFR_ID = #{mdfrId}
        WHERE DSCS_CMNT_ID = #{cmntSn}

		/*
			 토론방 댓글 삭제
			 ForumCmntDAO.deleteCmnt
		*/
        UPDATE TB_LMS_DSCS_CMNT
        SET DELYN = 'Y'
          , MOD_DTTM = FN_DTTM()
          , MDFR_ID = #{mdfrId}
        WHERE DSCS_CMNT_ID = #{cmntSn}

mapper.select:
/* 토론 댓글 목록 ForumCmntDAO.cmntList */ WITH OPNN ( RN, DSCS_CMNT_ID, DSCS_ATCL_ID, UP_CMNT_ID, CMNT_CTS, CMNT_CTS_LEN, EMT_TYCD/*, RGTRNM*/, RGTR_ID, REG_DTTM, MDFR_ID, MOD_DTTM, DELYN, RSPNS_REQYN, USER_ID, CHILD_YN, LVL, PATH ) AS ( SELECT ROW_NUMBER() OVER (ORDER BY A.REG_DTTM DESC, A.DSCS_CMNT_ID) AS RN , A.DSCS_CMNT_ID , A.DSCS_ATCL_ID , A.UP_CMNT_ID , A.CMNT_CTS , A.CMNT_CTS_LEN , A.EMT_TYCD -- , A.RGTRNM , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , A.RSPNS_REQYN , A.USER_ID , CASE WHEN C.UP_CMNT_ID IS NOT NULL THEN 'Y' ELSE 'N' END AS CHILD_YN , 1 AS LVL , LPAD(A.DSCS_CMNT_ID, 20, '0') AS PATH FROM TB_LMS_DSCS_CMNT A LEFT JOIN ( SELECT DISTINCT UP_CMNT_ID FROM TB_LMS_DSCS_CMNT WHERE DELYN = 'N' ) C ON C.UP_CMNT_ID = A.DSCS_CMNT_ID WHERE A.UP_CMNT_ID IS NULL AND A.DSCS_ATCL_ID = #{atclSn}
UNION ALL
SELECT B.RN , A.DSCS_CMNT_ID , A.DSCS_ATCL_ID , A.UP_CMNT_ID , A.CMNT_CTS , A.CMNT_CTS_LEN , A.EMT_TYCD -- , A.RGTRNM , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , A.RSPNS_REQYN , A.USER_ID , CASE WHEN C.UP_CMNT_ID IS NOT NULL THEN 'Y' ELSE 'N' END AS CHILD_YN , B.LVL + 1 AS LVL , B.PATH || '-' || LPAD(A.DSCS_CMNT_ID, 20, '0') AS PATH FROM TB_LMS_DSCS_CMNT A JOIN OPNN B ON A.UP_CMNT_ID = B.DSCS_CMNT_ID LEFT JOIN ( SELECT DISTINCT UP_CMNT_ID FROM TB_LMS_DSCS_CMNT WHERE DELYN = 'N' ) C ON C.UP_CMNT_ID = A.DSCS_CMNT_ID WHERE A.DSCS_ATCL_ID = #{atclSn} ) SELECT A.DSCS_CMNT_ID as CMNT_SN , A.DSCS_ATCL_ID as ATCL_SN , A.UP_CMNT_ID as PAR_CMNT_SN , PU.USERNM AS PAR_RGTR_NM , TO_CHAR(A.CMNT_CTS) AS CMNT_CTS , A.CMNT_CTS_LEN , A.EMT_TYCD as EMOTICON_NO , U.USERNM AS RGTRNM /*, A.RGTR_ID as stdId*/ , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , A.RSPNS_REQYN as ANS_REQ_YN , A.USER_ID as STD_ID , A.LVL - 1 AS LVL , A.PATH
, '' AS PHT_FILE_BYTE FROM OPNN A LEFT JOIN TB_LMS_USER U ON U.USER_ID = A.RGTR_ID LEFT JOIN TB_LMS_DSCS_CMNT PC ON PC.DSCS_CMNT_ID = A.UP_CMNT_ID LEFT JOIN TB_LMS_USER PU ON PU.USER_ID = PC.USER_ID WHERE (A.DELYN = 'N' OR A.CHILD_YN = 'Y') ORDER BY A.RN, A.PATH
